interface SidebarProps {
  role: UserRole;
  onLogout: () => void;
  isOpen: boolean;
  onClose: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ role, onLogout, isOpen, onClose }) => {
  const location = useLocation();
  const items = NAVIGATION_ITEMS[role];

  return (
    <>
      {/* Mobile Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black/50 lg:hidden"
          onClick={onClose}
        />
      )}

      {/* Sidebar Container */}
      <div className={`
        fixed top-0 right-0 z-30 h-full w-64 bg-white shadow-2xl transition-transform duration-300 ease-in-out
        lg:translate-x-0 lg:static lg:h-screen
        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
      `}>
        <div className="flex flex-col h-full">
          {/* Logo Area */}
          <div className="p-6 flex items-center gap-3 border-b border-gray-100">
            <div className="w-10 h-10 rounded-xl overflow-hidden shadow-md bg-primary-500 flex items-center justify-center text-white font-bold">
               {/* Using placeholder logic for logo */}
               <img src={LOGO_URL} alt="Logo" className="w-full h-full object-cover" />
            </div>
            <h1 className="font-bold text-gray-800 text-lg leading-tight">
              {APP_NAME}
            </h1>
          </div>

          {/* Navigation Links */}
          <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
            {items.map((item) => {
              const Icon = item.icon;
              const isActive = location.pathname === item.path;

              return (
                <Link
                  key={item.path}
                  to={item.path}
                  onClick={() => window.innerWidth < 1024 && onClose()}
                  className={`
                    flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200
                    ${isActive 
                      ? 'bg-primary-50 text-primary-600 font-semibold shadow-sm' 
                      : 'text-gray-500 hover:bg-gray-50 hover:text-gray-700'
                    }
                  `}
                >
                  <Icon size={20} className={isActive ? 'text-primary-600' : 'text-gray-400'} />
                  <span>{item.name}</span>
                </Link>
