          {/* Logout Button */}
          <div className="p-4 border-t border-gray-100">
            <button
              onClick={onLogout}
              className="flex items-center gap-3 px-4 py-3 w-full rounded-xl text-red-500 hover:bg-red-50 transition-colors"
            >
              <LogOut size={20} />
