import React, { useState, useEffect } from 'react';
import { Target, RefreshCw, CheckCircle, XCircle } from 'lucide-react';

// Simple Math Game Logic
const generateQuestion = () => {
    const ops = ['+', '-'];
    const op = ops[Math.floor(Math.random() * ops.length)];
    const a = Math.floor(Math.random() * 20) + 1;
    const b = Math.floor(Math.random() * 20) + 1;
    const ans = op === '+' ? a + b : a - b;

    // Generate distractors
    const answers = new Set([ans]);
    while (answers.size < 4) {
        answers.add(ans + Math.floor(Math.random() * 10) - 5);
    }

    return {
        q: `${a} ${op} ${b} = ?`,
        a: ans,
        options: Array.from(answers).sort(() => Math.random() - 0.5)
    };
};

export const GameZone: React.FC = () => {
  const [question, setQuestion] = useState(generateQuestion());
  const [score, setScore] = useState(0);
  const [feedback, setFeedback] = useState<'correct' | 'wrong' | null>(null);
  const [streak, setStreak] = useState(0);

  const handleAnswer = (val: number) => {
      if (feedback) return; // Prevent double clicks

      if (val === question.a) {
          setScore(s => s + 10 + (streak * 2));
          setStreak(s => s + 1);
          setFeedback('correct');
      } else {
          setStreak(0);
          setFeedback('wrong');
      }

      setTimeout(() => {
          setFeedback(null);
          setQuestion(generateQuestion());
      }, 1000);
  };

  return (
    <div className="min-h-[500px] flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-xl overflow-hidden border-4 border-primary-100">
            {/* Game Header */}
            <div className="bg-primary-600 p-6 text-white flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <Target className="text-accent-400" />
                    <span className="font-bold text-xl">تحدي الأرقام</span>
                </div>
                <div className="text-right">
                    <p className="text-xs text-primary-200">النقاط</p>
                    <p className="font-mono font-bold text-2xl">{score}</p>
                </div>
            </div>

            {/* Game Board */}
            <div className="p-8 text-center relative">
                {/* Feedback Overlay */}
                {feedback && (
                    <div className={`absolute inset-0 flex items-center justify-center bg-white/90 backdrop-blur-sm z-10 animate-fade-in`}>
                        {feedback === 'correct' ? (
                            <div className="text-green-500 scale-150 transform transition-transform duration-300">
                                <CheckCircle size={80} />
                                <p className="font-bold text-lg mt-2">ممتاز!</p>
                            </div>
                        ) : (
                            <div className="text-red-500 scale-150 transform transition-transform duration-300">
                                <XCircle size={80} />
                                <p className="font-bold text-lg mt-2">حاول مرة أخرى</p>
                            </div>
                        )}
                    </div>
                )}

                <div className="mb-8">
                    <h3 className="text-5xl font-black text-gray-800 tracking-wider mb-2">{question.q}</h3>
                    <p className="text-gray-400 text-sm">اختر الإجابة الصحيحة</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    {question.options.map((opt, i) => (
                        <button
                            key={i}
                            onClick={() => handleAnswer(opt)}
                            className="h-16 rounded-2xl bg-gray-50 hover:bg-primary-50 hover:text-primary-600 border-2 border-gray-100 hover:border-primary-200 text-xl font-bold text-gray-600 transition-all duration-200 active:scale-95"
                        >
                            {opt}
                        </button>
                    ))}
                </div>
            </div>

            {/* Footer */}
            <div className="bg-gray-50 p-4 flex justify-between items-center text-sm text-gray-500">
                <span>🔥 تتابع: {streak}</span>
                <button 
                    onClick={() => { setScore(0); setStreak(0); setQuestion(generateQuestion()); }}
                    className="flex items-center gap-1 hover:text-primary-600"
                >
                    <RefreshCw size={14} /> إعادة اللعب
                </button>
            </div>
        </div>
    </div>
  );
};

import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Sidebar } from './components/Sidebar';
import { TopBar } from './components/TopBar';
import { Login } from './views/Login';
import { StudentDashboard } from './views/StudentDashboard';
import { SupervisorDashboard } from './views/SupervisorDashboard';
import { AdminDashboard } from './views/AdminDashboard';
import { GameZone } from './views/GameZone';
import { UserRole, User } from './types';
import { USERS } from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isSidebarOpen, setSidebarOpen] = useState(false);

  const handleLogin = (role: UserRole) => {
    let user = USERS.student;
    if (role === UserRole.SUPERVISOR) user = USERS.supervisor;
    if (role === UserRole.ADMIN) user = USERS.admin;
    setCurrentUser(user);
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <div className="flex min-h-screen bg-gray-50/50 text-gray-900 font-sans">
        <Sidebar 
          role={currentUser.role} 
          onLogout={handleLogout} 
          isOpen={isSidebarOpen}
          onClose={() => setSidebarOpen(false)}
        />

        <div className="flex-1 flex flex-col w-full">
          <TopBar 
            user={currentUser} 
            onMenuClick={() => setSidebarOpen(true)}
          />

