            <div className="bg-white/10 backdrop-blur-md p-4 rounded-2xl border border-white/20 flex gap-6">
                <div className="text-center">
                    <p className="text-brand-300 text-xs font-bold uppercase">{t('النقاط', 'XP')}</p>
                    <p className="text-2xl font-black text-yellow-400">1250</p>
                </div>
                <div className="w-px bg-white/20"></div>
                <div className="text-center">
                    <p className="text-brand-300 text-xs font-bold uppercase">{t('المستوى', 'Level')}</p>
                    <p className="text-2xl font-black text-white">5</p>
