                              {/* Status Badge */}
                              <div className="flex justify-end mb-4 h-6">
                                  {course.progress === 100 && (
                                      <span className="bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 text-xs font-bold px-3 py-1 rounded-full flex items-center gap-1">
