                                  )}
                              </div>

                              <div className="mt-6">
                                  <h3 className={`text-lg font-black mb-2 leading-tight ${isUnlocked ? 'text-gray-800 dark:text-white' : 'text-gray-500 dark:text-slate-500'}`}>
                                      {t(course.titleAr, course.titleEn)}
                                  </h3>
                                  <div className="flex items-center gap-2 mb-4">
                                      <span className="text-[10px] font-bold bg-gray-100 dark:bg-slate-700 text-gray-500 dark:text-gray-300 px-2 py-1 rounded-md">{t(course.level, course.level)}</span>
                                      <span className="text-[10px] font-bold bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-300 px-2 py-1 rounded-md">{course.hours}h</span>
                                  </div>

                                  {/* Skills */}
                                  <div className="flex flex-wrap gap-1 mb-4 h-12 overflow-hidden">
                                      {(t(course.skillsAr.join(','), course.skillsEn.join(','))).split(',').slice(0,2).map((skill, i) => (
                                          <span key={i} className="text-[10px] text-gray-400 dark:text-gray-500 border border-gray-100 dark:border-slate-700 px-2 py-0.5 rounded-full">
                                              {skill}
                                          </span>
                                      ))}
                                  </div>

                                  {/* Action Button */}
                                  <div className={`
                                      flex items-center justify-between mt-2 pt-4 border-t border-gray-50 dark:border-slate-700
                                      ${isUnlocked ? 'text-secondary-600 dark:text-secondary-400' : 'text-gray-300 dark:text-slate-600'}
                                  `}>
                                      <span className="font-bold text-sm">{isUnlocked ? t('ابــدأ', 'Start') : t('مغلق', 'Locked')}</span>
                                      <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${isUnlocked ? 'bg-secondary-50 dark:bg-secondary-900/30 group-hover:bg-secondary-600 dark:group-hover:bg-secondary-500 group-hover:text-white' : 'bg-gray-100 dark:bg-slate-700'}`}>
                                          <ChevronRight size={16} className={dir === 'rtl' ? 'rotate-180' : ''} />
                                      </div>
                                  </div>
                              </div>
                          </div>

                          {/* Level Number Watermark */}
                          <div className="absolute -right-2 -bottom-4 text-[5rem] font-black text-gray-100/50 dark:text-slate-800/50 -z-10 pointer-events-none">
                              {idx + 1}
                          </div>
                      </div>
                  );
              })}
          </div>
      </div>
    </div>
  );
};

import React from 'react';
import { useLocation, Link } from 'react-router-dom';
import { UserRole } from '../types';
import { NAVIGATION_ITEMS, LOGO_URL, APP_NAME } from '../constants';
import { LogOut } from 'lucide-react';
import { useLanguage } from '../LanguageContext';

interface SidebarProps {
  role: UserRole;
  onLogout: () => void;
  isOpen: boolean;
  onClose: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ role, onLogout, isOpen, onClose }) => {
  const location = useLocation();
  const items = NAVIGATION_ITEMS[role];
  const { t } = useLanguage();

  return (
    <>
      {/* Mobile Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black/80 lg:hidden backdrop-blur-sm transition-opacity"
          onClick={onClose}
        />
      )}

      {/* Sidebar Container */}
      <div className={`
        fixed top-0 right-0 z-30 h-full w-64 bg-brand-dark dark:bg-black shadow-2xl transition-transform duration-300 ease-in-out border-l border-brand-800 dark:border-slate-900
        lg:translate-x-0 lg:static lg:h-screen lg:border-l-0
        ${isOpen ? 'translate-x-0' : 'translate-x-full rtl:-translate-x-full'}
      `}>
        <div className="flex flex-col h-full">
          {/* Logo Area */}
          <div className="p-6 flex flex-col items-center gap-4 border-b border-brand-800 dark:border-slate-900 bg-brand dark:bg-slate-950 transition-colors">
            <div className="w-20 h-20 rounded-full overflow-hidden shadow-lg bg-white flex items-center justify-center ring-4 ring-brand-700 dark:ring-slate-800">
               <img src={LOGO_URL} alt="L&G" className="w-full h-full object-cover transform hover:scale-110 transition-transform duration-500" />
            </div>
            <div className="text-center">
              <h1 className="font-black text-white text-xl leading-none tracking-tight mb-1">
                L&G
              </h1>
              <span className="text-[10px] text-primary-300 uppercase tracking-widest bg-brand-800 dark:bg-slate-800 px-2 py-1 rounded-full">Learning & Growth</span>
            </div>
          </div>

          {/* Navigation Links */}
          <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
            {items.map((item) => {
              const Icon = item.icon;
              const isActive = location.pathname === item.path;

              return (
                <Link
                  key={item.path}
                  to={item.path}
                  onClick={() => window.innerWidth < 1024 && onClose()}
                  className={`
                    flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 group
                    ${isActive 
                      ? 'bg-secondary-600 text-white font-bold shadow-lg shadow-secondary-900/20' 
                      : 'text-primary-400 hover:bg-brand-800 dark:hover:bg-slate-900 hover:text-white'
                    }
                  `}
                >
                  <Icon size={20} className={`transition-colors ${isActive ? 'text-white' : 'text-primary-500 group-hover:text-secondary-400'}`} />
                  <span>{t(item.nameAr, item.nameEn)}</span>
                </Link>
              );
            })}
          </nav>

          {/* Logout Button */}
          <div className="p-4 border-t border-brand-800 dark:border-slate-900 bg-brand-dark dark:bg-black transition-colors">
            <button
              onClick={onLogout}
              className="flex items-center gap-3 px-4 py-3 w-full rounded-xl text-red-400 hover:bg-red-500/10 hover:text-red-300 transition-colors"
            >
              <LogOut size={20} />
              <span>{t('تسجيل الخروج', 'Logout')}</span>
            </button>
          </div>
        </div>
      </div>
    </>
  );
};
